package com.enterprise.auth.config;

import com.enterprise.auth.model.User;
import com.enterprise.auth.service.UserService;
import org.springframework.security.authentication.BadCredentialsException;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.authentication.dao.AbstractUserDetailsAuthenticationProvider;
import org.springframework.security.core.AuthenticationException;
import org.springframework.security.core.userdetails.UserDetails;
import org.springframework.security.crypto.password.PasswordEncoder;

public class UsernamePasswordAuthProvider extends AbstractUserDetailsAuthenticationProvider {

    private final UserService userService;
    private final PasswordEncoder encoder;

    public UsernamePasswordAuthProvider(UserService userService, PasswordEncoder encoder) {
        this.userService = userService;
        this.encoder = encoder;
    }

    @Override
    protected void additionalAuthenticationChecks(UserDetails userDetails, UsernamePasswordAuthenticationToken authentication) throws AuthenticationException {
        String presented = authentication.getCredentials() == null ? null : authentication.getCredentials().toString();
        if (presented == null || !encoder.matches(presented, userDetails.getPassword())) {
            throw new BadCredentialsException("Invalid credentials");
        }
    }

    @Override
    protected UserDetails retrieveUser(String username, UsernamePasswordAuthenticationToken authentication) throws AuthenticationException {
        User user = userService.findByUsername(username).orElseThrow(() -> new BadCredentialsException("Invalid credentials"));
        return org.springframework.security.core.userdetails.User
                .withUsername(user.getUsername())
                .password(user.getPasswordHash())
                .authorities("USER")
                .accountLocked(!user.isEnabled())
                .build();
    }
}

// File: src/main/java/com/enterprise/auth/security/AuthTokenService.java
package com.enterprise.auth.security;

import org.springframework.security.core.Authentication;
import org.springframework.stereotype.Service;

import java.time.Instant;
import java.util.Map;
import java.util.UUID;
import java.util.concurrent.ConcurrentHashMap;

@Service
public class AuthTokenService {

    public static class TokenInfo {
        public final String username;
        public final boolean mfaSatisfied;
        public final Instant expiresAt;

        public TokenInfo(String username, boolean mfaSatisfied, Instant expiresAt) {
            this.username = username;
            this.mfaSatisfied = mfaSatisfied;
            this.expiresAt = expiresAt;
        }
    }

    private final Map<String, TokenInfo> tokens = new ConcurrentHashMap<>();

    public String mintToken(String username, boolean mfaSatisfied, long ttlSeconds) {
        String token = UUID.randomUUID().toString();
        tokens.put(token, new TokenInfo(username, mfaSatisfied, Instant.now().plusSeconds(ttlSeconds)));
        return token;
    }

    public TokenInfo verify(String token) {
        if (token == null || token.isBlank()) return null;
        TokenInfo info = tokens.get(token);
        if (info == null) return null;
        if (Instant.now().isAfter(info.expiresAt)) {
            tokens.remove(token);
            return null;
        }
        return info;
    }

    public void revoke(String token) {
        if (token != null) tokens.remove(token);
    }
}

// File: src/main/java/com/enterprise/auth/security/AuthTokenFilter.java
package com.enterprise.auth.security;

import jakarta.servlet.FilterChain;
import jakarta.servlet.ServletException;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.web.filter.OncePerRequestFilter;

import java.io.IOException;
import java.util.List;

public class AuthTokenFilter extends OncePerRequestFilter {

    private final AuthTokenService tokenService;

    public AuthTokenFilter(AuthTokenService tokenService) {
        this.tokenService = tokenService;
    }

    @Override
    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response, FilterChain filterChain)
            throws ServletException, IOException {

        String auth = request.getHeader("Authorization");
        String token = null;
        if (auth != null && auth.startsWith("Bearer ")) {
            token = auth.substring("Bearer ".length()).trim();
        }

        AuthTokenService.TokenInfo info = tokenService.verify(token);
        if (info != null) {
            UsernamePasswordAuthenticationToken authentication = new UsernamePasswordAuthenticationToken(
                    info.username,
                    null,
                    List.of(new SimpleGrantedAuthority("USER"))
            );
            authentication.setDetails(info);
            SecurityContextHolder.getContext().setAuthentication(authentication);
        }

        filterChain.doFilter(request, response);
    }
}

