package com.enterprise.auth.service;

import com.enterprise.auth.model.BackupCode;
import com.enterprise.auth.model.User;
import com.enterprise.auth.repo.BackupCodeRepository;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.security.SecureRandom;
import java.time.Instant;
import java.util.ArrayList;
import java.util.Base64;
import java.util.List;

@Service
public class BackupCodeService {

    public record GeneratedCodes(List<String> plainCodes, int count) {}

    private final BackupCodeRepository backupCodeRepository;
    private final PasswordEncoder encoder;
    private final SecureRandom secureRandom = new SecureRandom();

    private final int count;
    private final int codeBytes;
    private final int groupSize;
    private final int groups;

    public BackupCodeService(BackupCodeRepository backupCodeRepository,
                             PasswordEncoder encoder,
                             @Value("${app.backupCodes.count:10}") int count,
                             @Value("${app.backupCodes.codeBytes:10}") int codeBytes,
                             @Value("${app.backupCodes.codeGroupSize:4}") int groupSize,
                             @Value("${app.backupCodes.codeGroups:3}") int groups) {
        this.backupCodeRepository = backupCodeRepository;
        this.encoder = encoder;
        this.count = count;
        this.codeBytes = codeBytes;
        this.groupSize = groupSize;
        this.groups = groups;
    }

    @Transactional
    public GeneratedCodes generateAndStoreForUser(User user) {
        backupCodeRepository.deleteByUser(user);

        List<String> plain = new ArrayList<>(count);
        List<BackupCode> entities = new ArrayList<>(count);

        for (int i = 0; i < count; i++) {
            String code = generateHumanCode();
            plain.add(code);
            String hash = encoder.encode(normalize(code));
            entities.add(BackupCode.of(user, hash));
        }

        backupCodeRepository.saveAll(entities);
        return new GeneratedCodes(plain, count);
    }

    @Transactional
    public boolean consumeBackupCode(User user, String presentedCode) {
        if (presentedCode == null) return false;
        String normalized = normalize(presentedCode);

        List<BackupCode> unused = backupCodeRepository.findUnusedByUser(user);
        for (BackupCode bc : unused) {
            if (encoder.matches(normalized, bc.getCodeHash())) {
                bc.setUsed(true);
                bc.setUsedAt(Instant.now());
                backupCodeRepository.save(bc);
                return true;
            }
        }
        return false;
    }

    public int remainingUnused(User user) {
        return backupCodeRepository.findUnusedByUser(user).size();
    }

    private String generateHumanCode() {
        byte[] bytes = new byte[codeBytes];
        secureRandom.nextBytes(bytes);
        String base = Base64.getUrlEncoder().withoutPadding().encodeToString(bytes).toUpperCase();
        base = base.replaceAll("[^A-Z0-9]", "");
        if (base.length() < groupSize * groups) {
            base = (base + "ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789").substring(0, groupSize * groups);
        } else {
            base = base.substring(0, groupSize * groups);
        }

        StringBuilder sb = new StringBuilder();
        for (int g = 0; g < groups; g++) {
            if (g > 0) sb.append("-");
            int start = g * groupSize;
            sb.append(base, start, start + groupSize);
        }
        return sb.toString();
    }

    private String normalize(String code) {
        return code.trim().replace("-", "").replace(" ", "").toUpperCase();
    }
}

