package com.enterprise.auth.web;

import com.enterprise.auth.model.User;
import com.enterprise.auth.security.AuthTokenService;
import com.enterprise.auth.service.BackupCodeService;
import com.enterprise.auth.service.UserService;
import com.enterprise.auth.web.dto.*;
import jakarta.validation.Valid;
import org.springframework.security.authentication.AuthenticationManager;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.core.Authentication;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/auth")
public class AuthController {

    private final UserService userService;
    private final BackupCodeService backupCodeService;
    private final AuthenticationManager authenticationManager;
    private final AuthTokenService tokenService;

    public AuthController(UserService userService,
                          BackupCodeService backupCodeService,
                          AuthenticationManager authenticationManager,
                          AuthTokenService tokenService) {
        this.userService = userService;
        this.backupCodeService = backupCodeService;
        this.authenticationManager = authenticationManager;
        this.tokenService = tokenService;
    }

    @PostMapping("/register")
    public void register(@Valid @RequestBody RegisterRequest req) {
        userService.register(req.username, req.password);
    }

    @PostMapping("/login")
    public LoginResponse login(@Valid @RequestBody LoginRequest req) {
        Authentication auth = authenticationManager.authenticate(
                new UsernamePasswordAuthenticationToken(req.username, req.password)
        );

        User user = userService.findByUsername(auth.getName()).orElseThrow();

        if (user.isMfaEnabled()) {
            String mfaToken = tokenService.mintToken(user.getUsername(), false, 300);
            return LoginResponse.mfaRequired(mfaToken);
        }

        String accessToken = tokenService.mintToken(user.getUsername(), true, 3600);
        return LoginResponse.success(accessToken);
    }

    @PostMapping("/mfa/verify")
    public MfaVerifyResponse verifyMfa(@Valid @RequestBody MfaVerifyRequest req) {
        AuthTokenService.TokenInfo info = tokenService.verify(req.mfaToken);
        if (info == null || info.mfaSatisfied) {
            throw new IllegalArgumentException("Invalid MFA token");
        }

        User user = userService.findByUsername(info.username).orElseThrow();
        if (!user.isMfaEnabled()) {
            throw new IllegalArgumentException("MFA not enabled");
        }

        boolean ok = false;

        if (req.backupCode != null && !req.backupCode.isBlank()) {
            ok = backupCodeService.consumeBackupCode(user, req.backupCode);
        } else if (req.otp != null && !req.otp.isBlank()) {
            ok = false;
        }

        if (!ok) {
            throw new IllegalArgumentException("Invalid MFA verification");
        }

        tokenService.revoke(req.mfaToken);

        String accessToken = tokenService.mintToken(user.getUsername(), true, 3600);

        MfaVerifyResponse resp = new MfaVerifyResponse();
        resp.success = true;
        resp.accessToken = accessToken;
        resp.remainingBackupCodes = backupCodeService.remainingUnused(user);
        return resp;
    }
}

