@RestController
@RequestMapping("/api/mfa")
public class MfaController {

    private final UserService userService;
    private final BackupCodeService backupCodeService;

    public MfaController(UserService userService, BackupCodeService backupCodeService) {
        this.userService = userService;
        this.backupCodeService = backupCodeService;
    }

    @PostMapping("/enable")
    public EnableMfaResponse enable(Authentication authentication) {
        String username = authentication.getName();
        User user = userService.findByUsername(username).orElseThrow();

        userService.setMfaEnabled(user, true);

        BackupCodeService.GeneratedCodes codes = backupCodeService.generateAndStoreForUser(user);

        EnableMfaResponse resp = new EnableMfaResponse();
        resp.mfaEnabled = true;
        resp.backupCodes = codes.plainCodes();
        resp.count = codes.count();
        return resp;
    }

    @PostMapping("/regenerate-backup-codes")
    public EnableMfaResponse regenerate(Authentication authentication) {
        String username = authentication.getName();
        User user = userService.findByUsername(username).orElseThrow();

        if (!user.isMfaEnabled()) {
            throw new IllegalArgumentException("MFA not enabled");
        }

        BackupCodeService.GeneratedCodes codes = backupCodeService.generateAndStoreForUser(user);

        EnableMfaResponse resp = new EnableMfaResponse();
        resp.mfaEnabled = true;
        resp.backupCodes = codes.plainCodes();
        resp.count = codes.count();
        return resp;
    }

    @PostMapping("/disable")
    public void disable(Authentication authentication) {
        String username = authentication.getName();
        User user = userService.findByUsername(username).orElseThrow();

        userService.setMfaEnabled(user, false);
    }
}

// File: src/main/java/com/enterprise/auth/web/UserController.java
package com.enterprise.auth.web;

import com.enterprise.auth.model.User;
import com.enterprise.auth.security.AuthTokenService;
import com.enterprise.auth.service.UserService;
import com.enterprise.auth.web.dto.MeResponse;
import org.springframework.security.core.Authentication;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

@RestController
@RequestMapping("/api")
public class UserController {

    private final UserService userService;

    public UserController(UserService userService) {
        this.userService = userService;
    }

    @GetMapping("/me")
    public MeResponse me(Authentication authentication) {
        User user = userService.findByUsername(authentication.getName()).orElseThrow();
        MeResponse resp = new MeResponse();
        resp.username = user.getUsername();
        resp.mfaEnabled = user.isMfaEnabled();

        Object details = authentication.getDetails();
        boolean satisfied = false;
        if (details instanceof AuthTokenService.TokenInfo ti) {
            satisfied = ti.mfaSatisfied;
        }
        resp.mfaSatisfied = satisfied;
        return resp;
    }
}

// File: src/main/java/com/enterprise/auth/web/ApiExceptionHandler.java
package com.enterprise.auth.web;

import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.ExceptionHandler;
import org.springframework.web.bind.annotation.RestControllerAdvice;

import java.util.Map;

@RestControllerAdvice
public class ApiExceptionHandler {

    @ExceptionHandler(IllegalArgumentException.class)
    public ResponseEntity<?> handleIllegalArgument(IllegalArgumentException ex) {
        return ResponseEntity.status(HttpStatus.BAD_REQUEST).body(Map.of(
                "error", "bad_request",
                "message", ex.getMessage()
        ));
    }

    @ExceptionHandler(Exception.class)
    public ResponseEntity<?> handleOther(Exception ex) {
        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body(Map.of(
                "error", "server_error",
                "message", "Unexpected error"
        ));
    }
}